using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9: HasIndex throws for Cosmos entities ŌĆö removed.
        // Manage indexing via the Cosmos DB indexing policy (Azure Portal/Bicep).

        // EF Core 9: Discriminator property renamed to "$type" ŌĆö keep old name
        // so existing documents with "Discriminator" property remain readable.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // EF Core 9: id no longer includes discriminator ŌĆö keep old "Blog|1" format
        // so existing documents remain accessible via FindAsync / point-reads.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

